"use client"

import * as React from "react"
import { Badge, Tag, cn, formatCurrency } from "@gunjo/ui"
import type { TicketProduct } from "./types"
import { TAG_LABELS, TAG_BADGE_VARIANT } from "./data"

/**
 * GAP NOTE — the centerpiece "priced selectable product card".
 *
 * @gunjo/ui has no `RadioCard` / `SelectableCard`. The closest fit, `ListCard`,
 * renders a tappable card with `selected` + `onSelect` but exposes only
 * `aria-pressed` (toggle-button semantics), not single-select radio semantics —
 * and its `meta`/`tags`/`description` slots don't give the price + おトク額 the
 * hierarchy a store screen needs (price must dominate, おトク is the hook).
 *
 * So this is a deliberate hand-roll: a real WAI-ARIA `radio` (role="radio",
 * aria-checked) that lives inside the `radiogroup` rendered by ProductSelectGroup.
 * Everything *inside* it is still @gunjo/ui (Badge, Tag, formatCurrency, cn).
 * This is what a `RadioCard` in the kit would need to own.
 */
export interface ProductSelectCardProps {
  product: TicketProduct
  selected: boolean
  onSelect: (id: string) => void
  /** Roving-tabindex: only the checked card (or the first, if none) is tabbable. */
  tabbable: boolean
}

export function ProductSelectCard({
  product,
  selected,
  onSelect,
  tabbable,
}: ProductSelectCardProps) {
  const saving = Math.max(0, product.refFare - product.adultPrice)
  const descId = `${product.id}-detail`

  return (
    <div
      role="radio"
      aria-checked={selected}
      aria-describedby={descId}
      tabIndex={tabbable ? 0 : -1}
      onClick={() => onSelect(product.id)}
      onKeyDown={(e) => {
        if (e.key === " " || e.key === "Enter") {
          e.preventDefault()
          onSelect(product.id)
        }
      }}
      className={cn(
        "relative flex w-full cursor-pointer flex-col gap-2 rounded-lg border bg-card p-4 text-left transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        "hover:bg-accent/40",
        selected
          ? "border-ring ring-1 ring-ring bg-accent/30"
          : "border-border"
      )}
    >
      {/* selection check + tags row */}
      <div className="flex items-start justify-between gap-3">
        <div className="flex min-w-0 flex-wrap items-center gap-1.5">
          {product.tags.map((t) => (
            <Badge key={t} variant={TAG_BADGE_VARIANT[t]}>
              {TAG_LABELS[t]}
            </Badge>
          ))}
        </div>
        <span
          aria-hidden="true"
          className={cn(
            "mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center rounded-full border-2 transition-colors",
            selected ? "border-ring bg-ring text-background" : "border-input"
          )}
        >
          {selected ? (
            <svg viewBox="0 0 16 16" className="h-3 w-3" fill="none" stroke="currentColor" strokeWidth={2.5}>
              <path d="M3 8.5l3.5 3.5L13 4.5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          ) : null}
        </span>
      </div>

      {/* name + area + validity */}
      <div className="min-w-0">
        <h3 className="truncate text-base font-bold text-foreground">{product.name}</h3>
        <p id={descId} className="mt-0.5 text-sm text-muted-foreground">
          {product.area} ・ {product.validity}
        </p>
      </div>

      {/* price + おトク額 */}
      <div className="flex items-end justify-between gap-3">
        <div className="flex flex-col">
          {saving > 0 ? (
            <Tag variant="outline" size="sm" className="mb-1 w-fit border-success-border text-success-strong">
              {formatCurrency(saving)}分おトク
            </Tag>
          ) : null}
          <span className="text-xs text-muted-foreground">
            {product.breakEvenRides}回乗ればモト
          </span>
        </div>
        <div className="text-right">
          <span className="text-xs text-muted-foreground">おとな</span>
          <p className="text-xl font-bold tabular-nums text-foreground">
            {formatCurrency(product.adultPrice)}
          </p>
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { ProductSelectCard } from "./ProductSelectCard"
import type { TicketProduct } from "./types"

/**
 * The `radiogroup` container for priced product cards. This is the second half of
 * the hand-rolled centerpiece: @gunjo/ui's `RadioGroup` gives arrow-key roving
 * tabindex but only renders a 16px dot + label, while `ListCard` renders the rich
 * card but has no group/keyboard semantics. Neither alone is a "selectable priced
 * card group", so the keyboard wiring is reproduced here over rich card children.
 */
export interface ProductSelectGroupProps {
  products: TicketProduct[]
  value: string | null
  onChange: (id: string) => void
  label: string
}

export function ProductSelectGroup({
  products,
  value,
  onChange,
  label,
}: ProductSelectGroupProps) {
  const ref = React.useRef<HTMLDivElement>(null)

  const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if (!["ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End"].includes(e.key)) {
      return
    }
    const el = ref.current
    if (!el) return
    const radios = Array.from(el.querySelectorAll<HTMLElement>('[role="radio"]'))
    if (radios.length === 0) return
    e.preventDefault()
    const current = radios.indexOf(document.activeElement as HTMLElement)
    let next: number
    if (e.key === "Home") next = 0
    else if (e.key === "End") next = radios.length - 1
    else {
      const dir = e.key === "ArrowDown" || e.key === "ArrowRight" ? 1 : -1
      next = ((current === -1 ? 0 : current) + dir + radios.length) % radios.length
    }
    radios[next].focus()
    radios[next].click()
  }

  const firstId = products[0]?.id

  return (
    <div
      ref={ref}
      role="radiogroup"
      aria-label={label}
      onKeyDown={handleKeyDown}
      className="grid gap-3"
    >
      {products.map((p) => (
        <ProductSelectCard
          key={p.id}
          product={p}
          selected={value === p.id}
          onSelect={onChange}
          tabbable={value ? value === p.id : p.id === firstId}
        />
      ))}
    </div>
  )
}

"use client"

import * as React from "react"
import { ja } from "date-fns/locale"
import {
  Button,
  ToggleGroup,
  ToggleGroupItem,
  NumberInput,
  DatePicker,
  AmountBreakdown,
  Stepper,
  Badge,
  Tag,
  Banner,
  Alert,
  AlertTitle,
  AlertDescription,
  MetadataList,
  Accordion,
  AccordionItem,
  AccordionTrigger,
  AccordionContent,
  Separator,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  EmptyState,
  formatCurrency,
  cn,
} from "@gunjo/ui"
import {
  IconArrowLeft,
  IconShoppingCart,
  IconTicket,
  IconCircleCheck,
  IconInfoCircle,
  IconCalendarEvent,
} from "@tabler/icons-react"

import type {
  TicketProduct,
  TicketCategory,
  PurchaseStep,
  TicketTag,
} from "./types"
import {
  TICKETS,
  CATEGORY_LABELS,
  CATEGORY_ORDER,
  TAG_LABELS,
  TAG_BADGE_VARIANT,
} from "./data"
import { ProductSelectGroup } from "./ProductSelectGroup"

const STEP_LABELS: Record<PurchaseStep, string> = {
  select: "商品選択",
  options: "枚数・利用日",
  confirm: "確認",
  done: "完了",
}
const STEP_ORDER: PurchaseStep[] = ["select", "options", "confirm", "done"]

function isWeekend(d: Date): boolean {
  const day = d.getDay()
  return day === 0 || day === 6
}

function formatJaDate(d: Date): string {
  return new Intl.DateTimeFormat("ja-JP", {
    year: "numeric",
    month: "long",
    day: "numeric",
    weekday: "short",
  }).format(d)
}

export function TicketStore() {
  const [step, setStep] = React.useState<PurchaseStep>("select")
  const [category, setCategory] = React.useState<TicketCategory>("all")
  const [selectedId, setSelectedId] = React.useState<string | null>(null)
  const [detailId, setDetailId] = React.useState<string | null>(null)
  const [adultQty, setAdultQty] = React.useState(1)
  const [childQty, setChildQty] = React.useState(0)
  const [startDate, setStartDate] = React.useState<Date | undefined>(undefined)

  const filtered = React.useMemo(
    () =>
      category === "all"
        ? TICKETS
        : TICKETS.filter((t) => t.category === category),
    [category]
  )

  const selected = React.useMemo(
    () => TICKETS.find((t) => t.id === selectedId) ?? null,
    [selectedId]
  )
  const detailProduct = React.useMemo(
    () => TICKETS.find((t) => t.id === detailId) ?? null,
    [detailId]
  )

  // 金額の内訳
  const adultTotal = selected ? selected.adultPrice * adultQty : 0
  const childTotal = selected ? selected.childPrice * childQty : 0
  const subtotal = adultTotal + childTotal
  const totalQty = adultQty + childQty
  // モバイルきっぷ割引: 3枚以上で 100円/枚 off の例
  const discountPerTicket = totalQty >= 3 ? 100 : 0
  const discount = discountPerTicket * totalQty
  const payable = Math.max(0, subtotal - discount)

  // 利用開始日の制約
  const today = React.useMemo(() => {
    const d = new Date()
    d.setHours(0, 0, 0, 0)
    return d
  }, [])
  // weekend-only tickets block non-weekend days at the calendar level
  // (disabledDates), so a selected startDate is always valid here.
  const canProceedOptions = !!selected && totalQty >= 1 && !!startDate

  const currentStepIndex = STEP_ORDER.indexOf(step)
  const stepperSteps = STEP_ORDER.filter((s) => s !== "done").map((s) => ({
    label: STEP_LABELS[s],
    state:
      STEP_ORDER.indexOf(s) < currentStepIndex
        ? ("completed" as const)
        : STEP_ORDER.indexOf(s) === currentStepIndex
        ? ("current" as const)
        : ("upcoming" as const),
  }))

  function resetAll() {
    setStep("select")
    setSelectedId(null)
    setAdultQty(1)
    setChildQty(0)
    setStartDate(undefined)
    setCategory("all")
  }

  function goToOptions() {
    if (!selectedId) return
    setStep("options")
    window.scrollTo({ top: 0 })
  }

  return (
    <div className="mx-auto w-full max-w-md px-4 pb-28 pt-3">
      {/* progress */}
      {step !== "done" && (
        <Stepper steps={stepperSteps} className="px-0 pb-2 pt-0" aria-label="購入ステップ" />
      )}

      {step === "select" && (
        <SelectStep
          category={category}
          onCategoryChange={setCategory}
          products={filtered}
          selectedId={selectedId}
          onSelectProduct={setSelectedId}
          onOpenDetail={setDetailId}
        />
      )}

      {step === "options" && selected && (
        <OptionsStep
          product={selected}
          adultQty={adultQty}
          childQty={childQty}
          onAdultQty={setAdultQty}
          onChildQty={setChildQty}
          startDate={startDate}
          onStartDate={setStartDate}
          today={today}
          subtotal={subtotal}
          adultTotal={adultTotal}
          childTotal={childTotal}
          discount={discount}
          discountPerTicket={discountPerTicket}
          payable={payable}
          onBack={() => setStep("select")}
        />
      )}

      {step === "confirm" && selected && startDate && (
        <ConfirmStep
          product={selected}
          adultQty={adultQty}
          childQty={childQty}
          startDate={startDate}
          adultTotal={adultTotal}
          childTotal={childTotal}
          discount={discount}
          discountPerTicket={discountPerTicket}
          payable={payable}
          totalQty={totalQty}
          onBack={() => setStep("options")}
        />
      )}

      {step === "done" && selected && startDate && (
        <DoneStep
          product={selected}
          startDate={startDate}
          totalQty={totalQty}
          payable={payable}
          onReset={resetAll}
        />
      )}

      {/* sticky purchase bar */}
      {step === "select" && (
        <StickyBar
          disabled={!selected}
          label={selected ? `${selected.name} を選択中` : "きっぷを選んでください"}
          price={selected ? formatCurrency(selected.adultPrice) : undefined}
          cta="枚数・利用日へ"
          onClick={goToOptions}
        />
      )}
      {step === "options" && (
        <StickyBar
          disabled={!canProceedOptions}
          label="お支払い金額"
          price={formatCurrency(payable)}
          cta="確認へ進む"
          onClick={() => {
            setStep("confirm")
            window.scrollTo({ top: 0 })
          }}
        />
      )}
      {step === "confirm" && (
        <StickyBar
          disabled={false}
          label="お支払い金額"
          price={formatCurrency(payable)}
          cta={`${formatCurrency(payable)} を支払う`}
          onClick={() => {
            setStep("done")
            window.scrollTo({ top: 0 })
          }}
          icon={<IconShoppingCart className="h-4 w-4" aria-hidden="true" />}
        />
      )}

      {/* product detail sheet */}
      <ProductDetailSheet
        product={detailProduct}
        open={!!detailProduct}
        onClose={() => setDetailId(null)}
        onSelect={(id) => {
          setSelectedId(id)
          setDetailId(null)
        }}
      />
    </div>
  )
}

/* ───────────────────────── Step: 商品選択 ───────────────────────── */

function SelectStep({
  category,
  onCategoryChange,
  products,
  selectedId,
  onSelectProduct,
  onOpenDetail,
}: {
  category: TicketCategory
  onCategoryChange: (c: TicketCategory) => void
  products: TicketProduct[]
  selectedId: string | null
  onSelectProduct: (id: string) => void
  onOpenDetail: (id: string) => void
}) {
  return (
    <section aria-label="きっぷを選ぶ">
      <h1 className="mb-1 text-lg font-bold text-foreground">おトクなきっぷ</h1>
      <p className="mb-3 text-sm text-muted-foreground">
        一日乗車券・フリーきっぷから、おでかけに合う1枚を選べます。
      </p>

      {/* category / area filter */}
      <div className="-mx-4 mb-3 overflow-x-auto px-4">
        <ToggleGroup
          type="single"
          value={category}
          onValueChange={(v) => v && onCategoryChange(v as TicketCategory)}
          disallowEmpty
          variant="outline"
          className="w-max justify-start gap-2"
          aria-label="種類でしぼり込む"
        >
          {CATEGORY_ORDER.map((c) => (
            <ToggleGroupItem key={c} value={c} className="whitespace-nowrap">
              {CATEGORY_LABELS[c]}
            </ToggleGroupItem>
          ))}
        </ToggleGroup>
      </div>

      {products.length === 0 ? (
        <EmptyState
          title="該当するきっぷがありません"
          description="しぼり込み条件を変えてお試しください。"
        />
      ) : (
        <>
          <ProductSelectGroup
            products={products}
            value={selectedId}
            onChange={onSelectProduct}
            label="きっぷの商品"
          />
          {/* detail links — outside the radiogroup so they aren't radio stops */}
          <div className="mt-2 grid gap-1">
            {products.map((p) => (
              <button
                key={p.id}
                type="button"
                onClick={() => onOpenDetail(p.id)}
                className="w-fit px-1 py-0.5 text-left text-xs font-medium text-primary underline-offset-2 hover:underline focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
              >
                {p.name} の詳細・利用条件を見る →
              </button>
            ))}
          </div>
        </>
      )}
    </section>
  )
}

/* ───────────────────────── Step: 枚数・利用日 ───────────────────────── */

function OptionsStep(props: {
  product: TicketProduct
  adultQty: number
  childQty: number
  onAdultQty: (n: number) => void
  onChildQty: (n: number) => void
  startDate: Date | undefined
  onStartDate: (d: Date | undefined) => void
  today: Date
  subtotal: number
  adultTotal: number
  childTotal: number
  discount: number
  discountPerTicket: number
  payable: number
  onBack: () => void
}) {
  const {
    product,
    adultQty,
    childQty,
    onAdultQty,
    onChildQty,
    startDate,
    onStartDate,
    today,
    adultTotal,
    childTotal,
    discount,
    discountPerTicket,
    payable,
    onBack,
  } = props

  return (
    <section aria-label="枚数と利用日を選ぶ">
      <BackLink onClick={onBack} label="商品選択へ戻る" />

      {/* selected product summary */}
      <div className="mb-4 flex items-center gap-3 rounded-lg border bg-card p-3">
        <IconTicket className="h-6 w-6 shrink-0 text-primary" aria-hidden="true" />
        <div className="min-w-0 flex-1">
          <p className="truncate font-bold text-foreground">{product.name}</p>
          <p className="truncate text-xs text-muted-foreground">
            {product.area} ・ {product.validity}
          </p>
        </div>
        {product.tags[0] && (
          <Badge variant={TAG_BADGE_VARIANT[product.tags[0]]}>
            {TAG_LABELS[product.tags[0]]}
          </Badge>
        )}
      </div>

      {/* 枚数 */}
      <h2 className="mb-2 text-sm font-bold text-foreground">枚数</h2>
      <div className="mb-4 grid gap-3 rounded-lg border bg-card p-4">
        <QtyRow
          label="おとな"
          sub={formatCurrency(product.adultPrice)}
          value={adultQty}
          min={0}
          max={10}
          onChange={onAdultQty}
        />
        <Separator />
        <QtyRow
          label="こども"
          sub={
            product.childPrice > 0
              ? formatCurrency(product.childPrice)
              : "設定なし"
          }
          value={childQty}
          min={0}
          max={10}
          onChange={onChildQty}
          disabled={product.childPrice === 0}
        />
      </div>

      {/* 利用開始日 */}
      <h2 className="mb-2 text-sm font-bold text-foreground">利用開始日</h2>
      <div className="mb-2">
        <DatePicker
          value={startDate}
          onValueChange={onStartDate}
          locale={ja}
          placeholder="日付を選ぶ"
          calendarLabel="カレンダーを開く"
          editable={false}
          disabledDates={
            product.weekendOnly
              ? [{ before: today }, (d: Date) => !isWeekend(d)]
              : { before: today }
          }
          getDisabledReason={
            product.weekendOnly
              ? (d: Date) => (!isWeekend(d) ? "土休日のみ利用できます" : undefined)
              : undefined
          }
        />
      </div>
      {product.weekendOnly && (
        <Alert variant="warning" className="mb-2">
          <IconInfoCircle className="h-4 w-4" aria-hidden="true" />
          <AlertTitle>土休日限定のきっぷです</AlertTitle>
          <AlertDescription>
            利用開始日は土曜・休日のみ選べます（平日は選択できません）。
          </AlertDescription>
        </Alert>
      )}

      <Separator className="my-4" />

      {/* 金額の内訳 */}
      <h2 className="mb-2 text-sm font-bold text-foreground">金額の内訳</h2>
      <div className="rounded-lg border bg-card p-4">
        <AmountBreakdown
          lines={buildLines({
            product,
            adultQty,
            childQty,
            adultTotal,
            childTotal,
            discount,
            discountPerTicket,
          })}
          total={{ label: "お支払い金額", amount: payable, tone: "neutral" }}
          formula="お支払い金額 = (おとな + こども) − モバイル割引"
        />
      </div>
    </section>
  )
}

function QtyRow({
  label,
  sub,
  value,
  min,
  max,
  onChange,
  disabled,
}: {
  label: string
  sub: string
  value: number
  min: number
  max: number
  onChange: (n: number) => void
  disabled?: boolean
}) {
  return (
    <div className="flex items-center justify-between gap-3">
      <div className="min-w-0">
        <p className={cn("text-sm font-medium", disabled && "text-muted-foreground")}>
          {label}
        </p>
        <p className="text-xs text-muted-foreground tabular-nums">{sub}</p>
      </div>
      <NumberInput
        layout="stepper"
        value={value}
        min={min}
        max={max}
        onValueChange={onChange}
        disabled={disabled}
        incrementLabel={`${label}を1枚増やす`}
        decrementLabel={`${label}を1枚減らす`}
        aria-label={`${label}の枚数`}
      />
    </div>
  )
}

/* ───────────────────────── Step: 確認 ───────────────────────── */

function ConfirmStep(props: {
  product: TicketProduct
  adultQty: number
  childQty: number
  startDate: Date
  adultTotal: number
  childTotal: number
  discount: number
  discountPerTicket: number
  payable: number
  totalQty: number
  onBack: () => void
}) {
  const {
    product,
    adultQty,
    childQty,
    startDate,
    adultTotal,
    childTotal,
    discount,
    discountPerTicket,
    payable,
    onBack,
  } = props

  const metaItems = [
    { label: "商品", value: product.name },
    { label: "有効エリア", value: product.area },
    { label: "有効期間", value: product.validity },
    { label: "利用開始日", value: formatJaDate(startDate) },
    {
      label: "枚数",
      value: (
        <span className="tabular-nums">
          おとな {adultQty}枚{childQty > 0 ? ` ・ こども ${childQty}枚` : ""}
        </span>
      ),
    },
  ]

  return (
    <section aria-label="購入内容の確認">
      <BackLink onClick={onBack} label="枚数・利用日へ戻る" />
      <h1 className="mb-3 text-lg font-bold text-foreground">ご購入内容の確認</h1>

      <div className="mb-4 rounded-lg border bg-card p-4">
        <MetadataList items={metaItems} layout="vertical" />
      </div>

      <h2 className="mb-2 text-sm font-bold text-foreground">金額の内訳</h2>
      <div className="mb-4 rounded-lg border bg-card p-4">
        <AmountBreakdown
          lines={buildLines({
            product,
            adultQty,
            childQty,
            adultTotal,
            childTotal,
            discount,
            discountPerTicket,
          })}
          total={{ label: "お支払い金額", amount: payable, tone: "neutral" }}
        />
      </div>

      <Banner variant="info" className="mb-2">
        利用開始日を過ぎると払戻しできません。利用開始前の払戻しには手数料220円がかかります。
      </Banner>
    </section>
  )
}

/* ───────────────────────── Step: 完了 ───────────────────────── */

function DoneStep({
  product,
  startDate,
  totalQty,
  payable,
  onReset,
}: {
  product: TicketProduct
  startDate: Date
  totalQty: number
  payable: number
  onReset: () => void
}) {
  return (
    <section aria-label="購入完了" className="pt-6">
      {/* Hand-rolled success state — @gunjo/ui's StatusScreen only ships
          error presets (404 / 500 / 403 / offline / maintenance), no success. */}
      <div className="mx-auto flex max-w-sm flex-col items-center text-center">
        <span
