function buildLines(args: {
  product: TicketProduct
  adultQty: number
  childQty: number
  adultTotal: number
  childTotal: number
  discount: number
  discountPerTicket: number
}) {
  const { product, adultQty, childQty, adultTotal, childTotal, discount, discountPerTicket } = args
  const lines: React.ComponentProps<typeof AmountBreakdown>["lines"] = [
    {
      label: `おとな ${adultQty}枚`,
      note: `${formatCurrency(product.adultPrice)} × ${adultQty}`,
      amount: adultTotal,
    },
  ]
  if (childQty > 0) {
    lines.push({
      label: `こども ${childQty}枚`,
      note: `${formatCurrency(product.childPrice)} × ${childQty}`,
      amount: childTotal,
    })
  }
  if (discount > 0) {
    lines.push({
      label: "モバイルきっぷ割引",
      note: `3枚以上 ${formatCurrency(discountPerTicket)}/枚`,
      amount: discount,
      kind: "subtract",
    })
  }
  return lines
}

// Shared domain types for the おトクなきっぷ / 一日乗車券 購入画面.
// Pure data — no function props, safe to import from Server Components.

export type TicketCategory = "all" | "oneday" | "free" | "tourist"

export type TicketTag = "popular" | "limited" | "tourist" | "weekend"

export interface TicketProduct {
  id: string
  /** 商品名 (例: 都区内パス) */
  name: string
  /** 種類カテゴリ */
  category: Exclude<TicketCategory, "all">
  /** 有効エリア / フリー区間 (短い見出し) */
  area: string
  /** 有効エリアの詳しい説明 */
  areaDetail: string
  /** 有効期間 (例: 当日限り / 2日間) */
  validity: string
  /** おとな価格 (円) */
  adultPrice: number
  /** こども価格 (円) */
  childPrice: number
  /** この区間を普通運賃で乗った場合のおおよその額 (おトク額の根拠) */
  refFare: number
  /** 「○回乗ればモト」の目安回数 */
  breakEvenRides: number
  /** 付与タグ */
  tags: TicketTag[]
  /** 利用条件 (土休日のみ 等)。空配列なら毎日利用可。 */
  conditions: string[]
  /** 注意事項 */
  notes: string[]
  /** 土休日限定か (利用日カレンダーの制御に使う) */
  weekendOnly: boolean
}

/** 購入フローのステップ。 */
export type PurchaseStep = "select" | "options" | "confirm" | "done"
